"""Unit tests for LoanCollection ADT."""import pytestfrom datetime import datetime, timedeltafrom src.models.loan import LoanRecordfrom src.collections.loan_collection import LoanCollectionclass TestLoanCollection:    """Test suite for LoanCollection."""    @pytest.fixture    def empty_collection(self):        return LoanCollection()    @pytest.fixture    def sample_loan(self):        return LoanRecord.create_loan("123", "M001", datetime(2024, 1, 1))    def test_add_loan_success(self, empty_collection, sample_loan):        empty_collection.add_loan(sample_loan)        assert empty_collection.count_active() == 1        assert empty_collection.get_active_loan_for_book("123") == sample_loan    def test_add_loan_duplicate_active_book_fails(self, empty_collection, sample_loan):        empty_collection.add_loan(sample_loan)        duplicate = LoanRecord.create_loan("123", "M002", datetime(2024, 1, 2))        with pytest.raises(ValueError, match="already has an active loan"):            empty_collection.add_loan(duplicate)    def test_get_loans_for_member(self, empty_collection):        loan1 = LoanRecord.create_loan("111", "M001", datetime(2024, 1, 1))        loan2 = LoanRecord.create_loan("222", "M001", datetime(2024, 1, 5))        loan2.mark_returned()        empty_collection.add_loan(loan1)        empty_collection.add_loan(loan2)        loans = empty_collection.get_loans_for_member("M001")        assert len(loans) == 2        active = empty_collection.get_active_loans_for_member("M001")        assert len(active) == 1        assert active[0] == loan1    def test_get_overdue_loans(self, empty_collection):        # Create a loan due 10 days ago        past_checkout = datetime.now() - timedelta(days=20)        overdue_loan = LoanRecord.create_loan("111", "M001", past_checkout)        empty_collection.add_loan(overdue_loan)        overdue = empty_collection.get_overdue_loans()        assert len(overdue) == 1        assert overdue[0] == overdue_loan